<style>
    @import url("https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,100..900;1,100..900&display=swap");

    :root {
        --black: #1e1e1e;
        --blue: #0075c4;
        --lightblue: #e5f4ff;
        --gray-border: 1px solid #d2d2d2;
    }

    * {
        box-sizing: border-box;
    }

    h1,
    h2,
    h3,
    h4,
    h5,
    h6,
    ul,
    li,
    p,
    a {
        margin: 0;
        padding: 0;
        text-decoration: none;
        line-height: 1;
    }

    body {
        font-family: "Montserrat", sans-serif;
        margin: 0;
        padding: 0;
        color: var(--black);
    }

    h1 {
        font-size: 23px;
        line-height: 1em;
    }

    h1 span {
        color: var(--blue);
        line-height: 1em;
    }

    h2 {
        font-size: 14px;
        font-weight: 700;
    }

    h3 {
        font-size: 12px;
        font-weight: 700;
        margin: 2px 0;
    }

    label {
        font-size: 12px;
        font-weight: 500;
    }

    p {
        font-size: 10px;
        font-weight: 400;
        line-height: 1.2;
    }

    .insp-form {
        max-width: 700px;
        margin: auto;
        margin-top: 100px !important;
        margin-bottom: 50px !important;
    }

    .wrapper {
        max-width: 700px;
        margin: auto;
    }

    table {
        width: 100%;
        border-collapse: collapse;
    }

    td {
        padding: 8px;
    }

    .p-0 {
        padding: 0 !important;
    }

    .main-table {
        border: var(--gray-border);
        border-radius: 6px;
        border-collapse: separate;
        border-spacing: 0px;
        overflow: hidden;
        margin-top: 15px;
    }

    .section-header {
        background-color: var(--lightblue);
        padding: 8px;
        text-align: left;
    }

    .header-blue {
        background-color: var(--lightblue);
        position: fixed;
        width: 100%;
        left: 0;
        top: 0;
        z-index: 100;
    }

    .order-list span {
        font-size: 10px;
        font-weight: 500;
        color: var(--black);
        padding-left: 10px;
        margin-right: 10px;
        position: relative;
        display: inline-block;
        line-height: 1;
    }

    .block-span span {
        display: block;
        margin: 2px 0;
    }

    .order-list span::before {
        position: absolute;
        content: "";
        z-index: -1;
        top: 4px;
        left: 0;
        background-color: var(--blue);
        width: 5px;
        height: 5px;
        border-radius: 50%;
    }

    .footer {
        background-color: var(--lightblue);
        position: fixed;
        width: 100%;
        bottom: 0;
        left: 0;
        z-index: 100;
    }

    .footer-bar td {
        padding: 10px 0;
        font-size: 10px;
        vertical-align: middle;
    }

    .footer-bar p {
        color: #000000;
        font-weight: 500;
        display: inline-block;
        margin-left: 4px;
        vertical-align: middle;
    }

    .footer img {
        vertical-align: middle;
    }

    @media print {
        @page {
            size: letter;
            margin: 0 0;

            @top-center {
                content: element(pageHeader);
            }

            @bottom-center {
                content: element(pageFooter);
            }
        }

        .header {
            top: 0;
        }

        .footer {
            bottom: 0;
        }

        .header-table,
        .footer-bar {
            margin: 0;
        }

        .footer-bar td {
            padding: 6px 8px;
        }

        .page-header {
            position: running(pageHeader);
        }

        .page-footer {
            position: running(pageFooter);
        }
    }
</style>

